var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서...... 여기에서 경비로 일하고 있었다고?","JPN":"それで……ここで警備に当たっていたと？","ENG":"So... You've been working here as guards?","TWN":"所以……妳是說你們在這裡當守衛？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"네, 에이미가 그렇게 된 이후로......","JPN":"ええ、エイミーの件以来……","ENG":"Yes. After what happened to Amy...","TWN":"嗯，自從艾米變成那樣以後……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"프리덤 라이더의 재정에 문제가 많았거든요......","JPN":"フリーダム・ライダーズの財政に色々問題があったんです。","ENG":"Freedom Riders ran into serious financial problems.","TWN":"自由騎士的財政就出現了很多問題。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"다들 빈둥댈 줄만 알았지 관리라는 걸 해봤을 리가 없으니까요.","JPN":"みんな遊んでばかりで、組織管理なんてさっぱりでしたからね。","ENG":"We knew how to goof around, but knew nothing about running an organization.","TWN":"因為大家都只知道遊手好閒，從來沒有試著要去管理。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"당신이 제일 많이 놀았잖아!!","JPN":"あなたが一番遊んでたでしょうが！！","ENG":"You were the worst among us all!","TWN":"妳就是那個玩最嗨的吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어, 어쨌든 그래서 우여곡절 끝에 블랙 네트워크에 올라온 의뢰광고를 보고 취업을 하기로 했죠.","JPN":"と、とにかく紆余曲折を経て、ブラックネットワークに掲載された依頼広告を見て応募したんです。","ENG":"A-anyway, we saw a job ad on the Dark Network and decided to apply for it.","TWN":"總、總之，經過一番周折，我們看到黑色網路上的委託廣告後，就決定去就職。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"침식체 상대보다는 그냥 창고 경비가 쉽고 안전할 것 같았거든요.","JPN":"侵食体を相手にするよりかは、倉庫の警備のほうが簡単で安全だと判断したんです。","ENG":"We thought guarding the storehouse would be much safer and easier than fighting C.O.s.","TWN":"比起對付侵蝕體，倉庫守衛的工作更加簡單而且安全。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그리고 마침 관리국에서 총동원령까지 내리는 통에 끌려가지 않는 것만도 다행이라고 생각했는데......","JPN":"ちょうど管理局から総動員令まで出されてて、そこに連れてかれないだけで胸をなでおろしてたら……","ENG":"Then the Administration issued a general mobilization order, and we were thinking that we had luck in our favor because they didn't come for us.","TWN":"而且管理局還下達了總動員令，所以當時就覺得，我們能不被拉去真的是太好了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"가, 갑자기 이 도시에도 침식재난이 터져서 침식체들이 몰려오지 뭐에요?","JPN":"と、突然この街にも侵食災害が起きて、侵食体が押し寄せてくるじゃありませんか。","ENG":"But all of a sudden, a Corruption Disaster broke out in the city and C.O.s started to converge on us!","TWN":"但誰知道這個城市會突然發生侵蝕災難，冒出一堆侵蝕體啊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이상침식사태 때문에 구조대도 올 리가 없고......","JPN":"異常侵食が多発しているせいで、救助隊が駆け付けてくれるわけないですし……","ENG":"We couldn't expect a rescue team either, with abnormal Corruption crises breaking out everywhere.","TWN":"因為異常侵蝕的事件，我們也不能指望救援隊來這裡……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"여기서 겨우겨우 현상유지만 하고 있는데 얼마나 더 버틸 수 있을지 몰랐거든요......","JPN":"ここの現状維持だけで精一杯で、あとどれくらい持ちこたえられるか不安だったんです……","ENG":"We were barely keeping ourselves together, now knowing how much longer we'd be able to last...","TWN":"我們好不容易才能維持現狀，但不知道能撐多久。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하, 하지만 이제 미나 양이 우릴 구하러 왔으니까요!","JPN":"で、でも、ミナさんがヒミコたちを助けにきてくれたので！","ENG":"B-but we're fine now, since you came to our rescue, Mina!","TWN":"可、可是現在米娜小姐來救我們了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이젠 살았어요!","JPN":"これで助かりました！","ENG":"We're saved!","TWN":"我們已經得救了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"미나 양! 우릴 구해 줄 거죠?!","JPN":"ミナさん！　助けてくれますよね！？","ENG":"Mina, you're going to get us out, aren't you?","TWN":"米娜小姐！妳會救我們吧？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"구해 줘요! 구해 줄 때까지 붙어서 안 떨어질 거야!","JPN":"助けてよ！　助けてくれるまで、ひっつき虫になるもん！","ENG":"You have to! I'm going to stick by you until you do!","TWN":"救救我們吧！除非妳答應幫我們，不然我們是不會放手的！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니...... 그게......","JPN":"いや……それはちょっと……","ENG":"Umm... Well...","TWN":"呃……這個……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERCHANT_EXTRA_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"MERCHANT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};